# guardrails hub install hub://guardrails/valid_range
# guardrails hub install hub://guardrails/detect_pii
# guardrails hub install hub://guardrails/regex_match

from guardrails import Guard, Validator, register_validator
from guardrails.hub import ValidRange, DetectPII, RegexMatch
from pydantic import BaseModel, Field
from typing import Optional
from datetime import date
import logging

logger = logging.getLogger(__name__)


@register_validator(name="valid_iso_date", data_type="string")
class ValidISODate(Validator):
    """Ensures the string is a valid ISO 8601 date (YYYY-MM-DD)."""

    def validate(self, value, metadata):
        try:
            date.fromisoformat(value)
            return self.pass_result(value)
        except ValueError:
            return self.fail_result(
                value,
                f"'{value}' is not a valid ISO 8601 date.",
            )


class ContractObligation(BaseModel):
    party: str = Field(
        description="Name of the obligated party (2-120 chars)",
        validators=[RegexMatch(pattern=r"^[A-Za-z0-9 ,.'()-]{2,120}$", on_fail="reask")],
    )
    obligation_text: str = Field(
        description="Exact quoted obligation, 20-500 chars",
        validators=[RegexMatch(pattern=r"^.{20,500}$", on_fail="reask")],
    )
    deadline: Optional[str] = Field(
        default=None,
        description="Deadline in ISO 8601 format (YYYY-MM-DD), or null if none",
        validators=[ValidISODate(on_fail="refrain")],
    )
    liability_cap_usd: Optional[float] = Field(
        default=None,
        description="Maximum liability in USD (0 to 1 billion), or null",
        validators=[ValidRange(min=0, max=1_000_000_000, on_fail="reask")],
    )


class ContractAnalysis(BaseModel):
    obligations: list[ContractObligation]
    risk_level: str = Field(
        description="One of: low, medium, high",
        validators=[RegexMatch(pattern=r"^(low|medium|high)$", on_fail="reask")],
    )


guard = Guard.for_pydantic(ContractAnalysis, num_reasks=2)
guard.use(
    DetectPII(
        pii_entities=["EMAIL_ADDRESS", "PHONE_NUMBER"],
        on_fail="exception",
    ),
    on="messages",
)


def analyze_contract_clause(clause_text: str, llm_api) -> ContractAnalysis | None:
    """Validate and extract structured data from a contract clause."""
    try:
        outcome = guard(
            llm_api,
            messages=[
                {"role": "system", "content": "Extract obligations from the contract clause as JSON."},
                {"role": "user", "content": clause_text},
            ],
        )
        if outcome.validation_passed:
            return outcome.validated_output
        logger.error("Contract validation failed", extra={"error": outcome.error})
    except Exception as exc:
        logger.error("Guard exception", extra={"error": str(exc)})
    return None
